def token_case(s):
    exceptions = ['URL', 'ID']
    tokens = s.strip().split('_')
    result = []

    for i, token in enumerate(tokens):
        if token.upper() in exceptions:
            result.append(token)
        elif i == 0:
            result.append(token.lower())
        else:
            result.append(token.capitalize())

    return ''.join(result)

# Edge case: Empty string
print(token_case(""))  # Output: ""
